import{_ as a,o as i,c as n,ah as t}from"./chunks/framework.ojwJKwrc.js";const k=JSON.parse('{"title":"組み合わせループ","description":"","frontmatter":{},"headers":[],"relativePath":"ja/guide/combinational-loops.md","filePath":"ja/guide/combinational-loops.md"}'),e={name:"ja/guide/combinational-loops.md"};function p(l,s,o,d,h,c){return i(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="組み合わせループ" tabindex="-1">組み合わせループ <a class="header-anchor" href="#組み合わせループ" aria-label="Permalink to &quot;組み合わせループ&quot;">​</a></h1><p>Celox は <code>always_comb</code> ブロックの依存関係を静的に解析してトポロジカル順序でスケジューリングします。依存グラフにサイクルを検出するとコンパイルが <code>CombinationalLoop</code> エラーで失敗します。</p><p>このエラーが発生する状況は 2 種類あり、それぞれ異なる対処が必要です。</p><h2 id="見かけ上のループ-falseloops" tabindex="-1">見かけ上のループ（<code>falseLoops</code>） <a class="header-anchor" href="#見かけ上のループ-falseloops" aria-label="Permalink to &quot;見かけ上のループ（\`falseLoops\`）&quot;">​</a></h2><p>静的な依存グラフ上にサイクルが現れるものの、実行時には決してループしない場合です。最もよくある原因は、2 つのブランチが互いに逆側のパスに依存しているマルチプレクサです：</p><div class="language-veryl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">veryl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>module Top (</span></span>
<span class="line"><span>    sel: input  logic,</span></span>
<span class="line"><span>    i:   input  logic&lt;2&gt;,</span></span>
<span class="line"><span>    o:   output logic&lt;2&gt;,</span></span>
<span class="line"><span>) {</span></span>
<span class="line"><span>    var v: logic&lt;2&gt;;</span></span>
<span class="line"><span>    always_comb {</span></span>
<span class="line"><span>        if sel {</span></span>
<span class="line"><span>            v[0] = v[1];  // v[1] を読む</span></span>
<span class="line"><span>            v[1] = i[1];</span></span>
<span class="line"><span>        } else {</span></span>
<span class="line"><span>            v[0] = i[0];</span></span>
<span class="line"><span>            v[1] = v[0];  // v[0] を読む</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    assign o = v;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><code>v[0]</code> と <code>v[1]</code> は互いに依存しているように見えますが、<code>v[0]→v[1]</code> は <code>sel=1</code> のとき、<code>v[1]→v[0]</code> は <code>sel=0</code> のときだけ起き、同時にループすることはありません。</p><p>そのままではコンパイルに失敗します。<code>falseLoops</code> でこのサイクルが安全であることを宣言します：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> sim</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Simulator.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fromSource</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">SOURCE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Top&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  falseLoops: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { from: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;v&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, to: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;v&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">});</span></span></code></pre></div><p><code>from</code> と <code>to</code> にはサイクルに関係するシグナル名を指定します。Celox は SCC ブロックをサイクルの構造的な深さから算出した回数だけ実行して、実行順序によらずすべての値が正しく伝搬するようにします。</p><h2 id="本物のフィードバックループ-trueloops" tabindex="-1">本物のフィードバックループ（<code>trueLoops</code>） <a class="header-anchor" href="#本物のフィードバックループ-trueloops" aria-label="Permalink to &quot;本物のフィードバックループ（\`trueLoops\`）&quot;">​</a></h2><p>本物の組み合わせフィードバックパスです。出力が入力に戻り、安定状態（固定点）に達するまで反復が必要です。</p><div class="language-veryl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">veryl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>module Top (i: input logic, o: output logic&lt;4&gt;) {</span></span>
<span class="line"><span>    var v: logic&lt;4&gt;;</span></span>
<span class="line"><span>    always_comb {</span></span>
<span class="line"><span>        v = {v[2:0], i};  // シフトレジスタ: 自分自身にフィードバック</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    assign o = v;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>デフォルトでは Celox はごく少ない反復回数しか許可しません（構造的なループ深さを基準にした上限値）。回路の収束にさらに多くの反復が必要な場合は <code>trueLoops</code> に十分な <code>maxIter</code> を指定します：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> sim</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Simulator.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fromSource</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">SOURCE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Top&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  trueLoops: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { from: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;v&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, to: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;v&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, maxIter: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">});</span></span></code></pre></div><p><code>maxIter</code> 回以内に収束しない場合、シミュレーションは実行時に <code>DetectedTrueLoop</code> エラーをスローします。</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>永遠に収束しないループ（例: <code>assign y = ~y</code>）は <code>maxIter</code> の値によらず常に実行時エラーになります。これは組み合わせ発振であり、有効なハードウェア状態ではありません。</p></div><h2 id="シグナルパスの書き方" tabindex="-1">シグナルパスの書き方 <a class="header-anchor" href="#シグナルパスの書き方" aria-label="Permalink to &quot;シグナルパスの書き方&quot;">​</a></h2><p><code>from</code> と <code>to</code> にはシグナルパス文字列を指定します：</p><table tabindex="0"><thead><tr><th>パターン</th><th>意味</th></tr></thead><tbody><tr><td><code>&quot;v&quot;</code></td><td>トップレベルの変数 <code>v</code></td></tr><tr><td><code>&quot;u_sub:i_data&quot;</code></td><td>子インスタンス <code>u_sub</code> のポート <code>i_data</code></td></tr><tr><td><code>&quot;u_a.u_b:x&quot;</code></td><td><code>u_a</code> 内の <code>u_b</code> インスタンスのポート <code>x</code></td></tr></tbody></table><h2 id="falseloops-と-trueloops-の使い分け" tabindex="-1"><code>falseLoops</code> と <code>trueLoops</code> の使い分け <a class="header-anchor" href="#falseloops-と-trueloops-の使い分け" aria-label="Permalink to &quot;\`falseLoops\` と \`trueLoops\` の使い分け&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th><code>falseLoops</code></th><th><code>trueLoops</code></th></tr></thead><tbody><tr><td>実行時に実際にループするか</td><td>しない（パスが排他的）</td><td>する（出力が入力にフィードバック）</td></tr><tr><td>反復の動作</td><td>構造的な深さ N 回のスタティックアンロール</td><td>収束または <code>maxIter</code> まで反復</td></tr><tr><td>実行時エラーの可能性</td><td>なし</td><td>収束しない場合にあり</td></tr></tbody></table><h2 id="関連資料" tabindex="-1">関連資料 <a class="header-anchor" href="#関連資料" aria-label="Permalink to &quot;関連資料&quot;">​</a></h2><ul><li><a href="/celox/internals/combinational-analysis.html">組み合わせ回路解析</a> -- 依存グラフの構築とスケジューリングの詳細。</li><li><a href="./writing-tests.html">テストの書き方</a> -- シミュレータオプションの概要。</li></ul>`,24)])])}const u=a(e,[["render",p]]);export{k as __pageData,u as default};
